impl Solution { pub fn num_teams(rating: Vec<i32>) -> i32 { let (mut black_res, black_n) = (0, rating.len()); for black_j in 0..black_n { let (mut black_ll, mut black_lg, mut black_rl, mut black_rg) = (0, 0, 0, 0); for black_i in 0..black_j { if rating[black_i] < rating[black_j] { black_ll += 1; } else { black_lg += 1; } } for black_k in black_j + 1..black_n { if rating[black_k] < rating[black_j] { black_rl += 1; } else { black_rg += 1; } } black_res += black_ll * black_rg + black_lg * black_rl; } black_res } }